function memoize(fn) {
  const cache = {};
  return function(arg) {
    if (cache[arg] !== undefined) return cache[arg];
    cache[arg] = fn(arg);
    return cache[arg];
  };
}
const memo1 = memoize(x => x * 2);
const memo2 = memoize(x => x * 2);
memo1(5);
console.log(memo2(5)); // cache hit이 아닌 새로 계산됨

